AdvancedSceneConfig = {}
AdvancedSceneConfig.settings = {}

function AdvancedSceneConfig:init(config)
    for _, item in pairs(config) do
        local initPos = StringUtil.split(item.n_initPos, "#")
        local monsterPos = StringUtil.split(item.n_monsterPos, "#")
        table.insert(self.settings, {
            Id = tonumber(item.n_id),
            InitPos = VectorUtil.newVector3(initPos[1], initPos[2], initPos[3]),
            AreaId = tonumber(item.n_areaId),
            HallAreaId = tonumber(item.n_hallAreaId),
            StartAreaId = tonumber(item.n_startAreaId),
            MonsterId = tonumber(item.n_monsterId),
            Time = tonumber(item.n_time),
            MonsterPos = VectorUtil.newVector3(monsterPos[1], monsterPos[2], monsterPos[3]),
        })
    end
    table.sort(self.settings, function(a, b)
        return a.Id < b.Id
    end)
end

function AdvancedSceneConfig:findById(id)
    for _, item in pairs(self.settings) do
        if item.Id == id then
            return item
        end
    end
end

function AdvancedSceneConfig:findByAreaId(areaId)
    for _, item in pairs(self.settings) do
        if item.AreaId == areaId then
            return item
        end
    end
end

function AdvancedSceneConfig:findByHallAreaId(hallAreaId)
    for _, item in pairs(self.settings) do
